'use client';

import React, { useState } from 'react';
import { useRouter } from 'next/navigation';
import { supabase } from '@/lib/supabase';

export default function UserRegisterPage() {
  const router = useRouter();
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (event: React.FormEvent) => {
    event.preventDefault();
    setLoading(true);
    setError('');
    setSuccess('');

    const { data, error } = await supabase.auth.signUp({
      email,
      password,
    });

    setLoading(false);

    if (error) {
      setError(error.message || 'Unable to register. Please try again.');
      return;
    }

    if (data.user) {
      setSuccess('Registration successful. Please check your email for verification.');
      setEmail('');
      setPassword('');
      return;
    }

    setSuccess('Registration request received. Please check your email to confirm your account.');
  };

  return (
    <div data-component-id="src\app\auth\register\page.tsx:44:4" data-component-path="src\app\auth\register\page.tsx" data-component-line="44" data-component-end-line="101" data-component-file="page.tsx" data-component-name="div" data-component-content="%7B%22elementName%22%3A%22div%22%2C%22className%22%3A%22min-h-screen%20flex%20items-center%20justify-center%20bg-slate-100%20px-4%20py-10%22%7D" className="min-h-screen flex items-center justify-center bg-slate-100 px-4 py-10">
      <div data-component-id="src\app\auth\register\page.tsx:45:6" data-component-path="src\app\auth\register\page.tsx" data-component-line="45" data-component-end-line="100" data-component-file="page.tsx" data-component-name="div" data-component-content="%7B%22elementName%22%3A%22div%22%2C%22className%22%3A%22w-full%20max-w-md%20bg-white%20rounded-3xl%20p-8%20shadow-xl%22%7D" className="w-full max-w-md bg-white rounded-3xl p-8 shadow-xl">
        <h1 data-component-id="src\app\auth\register\page.tsx:46:8" data-component-path="src\app\auth\register\page.tsx" data-component-line="46" data-component-end-line="46" data-component-file="page.tsx" data-component-name="h1" data-component-content="%7B%22elementName%22%3A%22h1%22%2C%22className%22%3A%22text-2xl%20font-semibold%20text-slate-900%20mb-4%22%2C%22textContent%22%3A%22Create%20an%20account%22%7D" className="text-2xl font-semibold text-slate-900 mb-4">Create an account</h1>
        <p data-component-id="src\app\auth\register\page.tsx:47:8" data-component-path="src\app\auth\register\page.tsx" data-component-line="47" data-component-end-line="47" data-component-file="page.tsx" data-component-name="p" data-component-content="%7B%22elementName%22%3A%22p%22%2C%22className%22%3A%22text-sm%20text-slate-500%20mb-6%22%2C%22textContent%22%3A%22Register%20with%20email%20and%20a%20secure%20password.%22%7D" className="text-sm text-slate-500 mb-6">Register with email and a secure password.</p>

        {error && (
          <div data-component-id="src\app\auth\register\page.tsx:50:10" data-component-path="src\app\auth\register\page.tsx" data-component-line="50" data-component-end-line="52" data-component-file="page.tsx" data-component-name="div" data-component-content="%7B%22elementName%22%3A%22div%22%2C%22className%22%3A%22mb-4%20rounded-xl%20bg-red-50%20border%20border-red-200%20p-4%20text-sm%20text-red-700%22%7D" className="mb-4 rounded-xl bg-red-50 border border-red-200 p-4 text-sm text-red-700">
            {error}
          </div>
        )}
        {success && (
          <div data-component-id="src\app\auth\register\page.tsx:55:10" data-component-path="src\app\auth\register\page.tsx" data-component-line="55" data-component-end-line="57" data-component-file="page.tsx" data-component-name="div" data-component-content="%7B%22elementName%22%3A%22div%22%2C%22className%22%3A%22mb-4%20rounded-xl%20bg-emerald-50%20border%20border-emerald-200%20p-4%20text-sm%20text-emerald-700%22%7D" className="mb-4 rounded-xl bg-emerald-50 border border-emerald-200 p-4 text-sm text-emerald-700">
            {success}
          </div>
        )}

        <form data-component-id="src\app\auth\register\page.tsx:60:8" data-component-path="src\app\auth\register\page.tsx" data-component-line="60" data-component-end-line="92" data-component-file="page.tsx" data-component-name="form" data-component-content="%7B%22elementName%22%3A%22form%22%2C%22className%22%3A%22space-y-4%22%7D" onSubmit={handleSubmit} className="space-y-4">
          <div data-component-id="src\app\auth\register\page.tsx:61:10" data-component-path="src\app\auth\register\page.tsx" data-component-line="61" data-component-end-line="71" data-component-file="page.tsx" data-component-name="div" data-component-content="%7B%22elementName%22%3A%22div%22%7D">
            <label data-component-id="src\app\auth\register\page.tsx:62:12" data-component-path="src\app\auth\register\page.tsx" data-component-line="62" data-component-end-line="62" data-component-file="page.tsx" data-component-name="label" data-component-content="%7B%22elementName%22%3A%22label%22%2C%22className%22%3A%22block%20text-sm%20font-medium%20text-slate-700%20mb-2%22%2C%22textContent%22%3A%22Email%22%7D" className="block text-sm font-medium text-slate-700 mb-2">Email</label>
            <input data-component-id="src\app\auth\register\page.tsx:63:12" data-component-path="src\app\auth\register\page.tsx" data-component-line="63" data-component-end-line="70" data-component-file="page.tsx" data-component-name="input" data-component-content="%7B%22elementName%22%3A%22input%22%2C%22type%22%3A%22email%22%2C%22value%22%3A%22%5Bvar%3Aemail%5D%22%2C%22className%22%3A%22w-full%20rounded-2xl%20border%20border-slate-200%20px-4%20py-3%20text-sm%20text-slate-900%20focus%3Aoutline-none%20focus%3Aring-2%20focus%3Aring-teal-500%22%7D"
              type="email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              required
              placeholder="you@example.com"
              className="w-full rounded-2xl border border-slate-200 px-4 py-3 text-sm text-slate-900 focus:outline-none focus:ring-2 focus:ring-teal-500"
            />
          </div>

          <div data-component-id="src\app\auth\register\page.tsx:73:10" data-component-path="src\app\auth\register\page.tsx" data-component-line="73" data-component-end-line="83" data-component-file="page.tsx" data-component-name="div" data-component-content="%7B%22elementName%22%3A%22div%22%7D">
            <label data-component-id="src\app\auth\register\page.tsx:74:12" data-component-path="src\app\auth\register\page.tsx" data-component-line="74" data-component-end-line="74" data-component-file="page.tsx" data-component-name="label" data-component-content="%7B%22elementName%22%3A%22label%22%2C%22className%22%3A%22block%20text-sm%20font-medium%20text-slate-700%20mb-2%22%2C%22textContent%22%3A%22Password%22%7D" className="block text-sm font-medium text-slate-700 mb-2">Password</label>
            <input data-component-id="src\app\auth\register\page.tsx:75:12" data-component-path="src\app\auth\register\page.tsx" data-component-line="75" data-component-end-line="82" data-component-file="page.tsx" data-component-name="input" data-component-content="%7B%22elementName%22%3A%22input%22%2C%22type%22%3A%22password%22%2C%22value%22%3A%22%5Bvar%3Apassword%5D%22%2C%22className%22%3A%22w-full%20rounded-2xl%20border%20border-slate-200%20px-4%20py-3%20text-sm%20text-slate-900%20focus%3Aoutline-none%20focus%3Aring-2%20focus%3Aring-teal-500%22%7D"
              type="password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              required
              placeholder="Create a password"
              className="w-full rounded-2xl border border-slate-200 px-4 py-3 text-sm text-slate-900 focus:outline-none focus:ring-2 focus:ring-teal-500"
            />
          </div>

          <button data-component-id="src\app\auth\register\page.tsx:85:10" data-component-path="src\app\auth\register\page.tsx" data-component-line="85" data-component-end-line="91" data-component-file="page.tsx" data-component-name="button" data-component-content="%7B%22elementName%22%3A%22button%22%2C%22type%22%3A%22submit%22%2C%22className%22%3A%22w-full%20rounded-2xl%20bg-%5B%230A1628%5D%20px-4%20py-3%20text-sm%20font-semibold%20text-white%20transition%20hover%3Abg-%5B%23081724%5D%20disabled%3Aopacity-70%22%7D"
            type="submit"
            disabled={loading}
            className="w-full rounded-2xl bg-[#0A1628] px-4 py-3 text-sm font-semibold text-white transition hover:bg-[#081724] disabled:opacity-70"
          >
            {loading ? 'Registering…' : 'Register'}
          </button>
        </form>

        <p data-component-id="src\app\auth\register\page.tsx:94:8" data-component-path="src\app\auth\register\page.tsx" data-component-line="94" data-component-end-line="99" data-component-file="page.tsx" data-component-name="p" data-component-content="%7B%22elementName%22%3A%22p%22%2C%22className%22%3A%22mt-6%20text-center%20text-sm%20text-slate-500%22%2C%22textContent%22%3A%22Already%20have%20an%20account%3F%22%7D" className="mt-6 text-center text-sm text-slate-500">
          Already have an account?{' '}
          <a data-component-id="src\app\auth\register\page.tsx:96:10" data-component-path="src\app\auth\register\page.tsx" data-component-line="96" data-component-end-line="98" data-component-file="page.tsx" data-component-name="a" data-component-content="%7B%22elementName%22%3A%22a%22%2C%22href%22%3A%22%2Fauth%2Flogin%22%2C%22className%22%3A%22font-semibold%20text-teal-600%20hover%3Atext-teal-700%22%2C%22textContent%22%3A%22Sign%20in%22%7D" href="/auth/login" className="font-semibold text-teal-600 hover:text-teal-700">
            Sign in
          </a>
        </p>
      </div>
    </div>
  );
}
